const update = $json;

const msg =
  update.message ||
  update.edited_message ||
  update.channel_post ||
  {};

const chatId = msg.chat?.id || null;
const userId = msg.from?.id || null;
const messageId = msg.message_id || null;

const text = (msg.text || msg.caption || "").trim();

const photos = msg.photo || [];
const largestPhoto = photos.length ? photos[photos.length - 1] : null;

let inputType = "unknown";

if (text === "/start" || text === "/help" || text.startsWith("/start ")) {
  inputType = "start";
} else if (largestPhoto && text) {
  inputType = "image_with_caption";
} else if (largestPhoto) {
  inputType = "image";
} else if (text) {
  inputType = "text";
}

return {
  json: {
    update_id: update.update_id || null,
    chat_id: chatId,
    user_id: userId,
    message_id: messageId,
    input_type: inputType,
    text,
    photo_file_id: largestPhoto?.file_id || null,
    photo_file_unique_id: largestPhoto?.file_unique_id || null,
    raw_message: msg
  }
};

