function getOpenAIText(data) {
  if (typeof data.output_text === "string") {
    return data.output_text;
  }

  const parts = [];

  for (const output of data.output || []) {
    for (const content of output.content || []) {
      if (typeof content.text === "string") {
        parts.push(content.text);
      }
    }
  }

  return parts.join("\n").trim();
}

function parseJsonLoose(text) {
  let cleaned = String(text || "").trim();

  cleaned = cleaned
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const first = cleaned.indexOf("{");
  const last = cleaned.lastIndexOf("}");

  if (first !== -1 && last !== -1 && last > first) {
    cleaned = cleaned.slice(first, last + 1);
  }

  return JSON.parse(cleaned);
}

const response = $input.first().json;
const base = $("Code in JavaScript").first().json;

const modelText = getOpenAIText(response);

let product;

try {
  product = parseJsonLoose(modelText);
} catch (error) {
  throw new Error(`Cannot parse product JSON. Raw model text:\n${modelText}`);
}

return [
  {
    json: {
      chat_id: base.chat_id,
      user_id: base.user_id,
      input_type: base.input_type,
      user_text: base.text,
      product
    }
  }
];

