function getOpenAIText(data) {
  if (typeof data.output_text === "string" && data.output_text.trim()) {
    return data.output_text.trim();
  }

  const parts = [];

  for (const output of data.output || []) {
    for (const content of output.content || []) {
      if (typeof content.text === "string" && content.text.trim()) {
        parts.push(content.text);
      }
    }
  }

  return parts.join("\n").trim();
}

function parseJsonLoose(text) {
  let cleaned = String(text || "").trim();

  cleaned = cleaned
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const first = cleaned.indexOf("{");
  const last = cleaned.lastIndexOf("}");

  if (first !== -1 && last !== -1 && last > first) {
    cleaned = cleaned.slice(first, last + 1);
  }

  if (!cleaned) {
    throw new Error("Empty text. No JSON to parse.");
  }

  return JSON.parse(cleaned);
}

function list(value) {
  if (Array.isArray(value)) {
    if (value.length === 0) return "—";
    return value.map(x => `• ${x}`).join("\n");
  }

  if (typeof value === "string" && value.trim()) {
    return `• ${value.trim()}`;
  }

  return "—";
}

function formatCharacteristics(obj) {
  if (!obj || typeof obj !== "object" || !Object.keys(obj).length) {
    return "—";
  }

  return Object.entries(obj)
    .map(([key, value]) => {
      const v = Array.isArray(value) ? value.join(", ") : value;
      return `• ${key}: ${v}`;
    })
    .join("\n");
}

function cleanMissingData(value) {
  if (!Array.isArray(value)) return [];

  const ignored = [
    "цена",
    "стоимость",
    "visible_price",
    "price"
  ];

  return value.filter(item => {
    const text = String(item || "").toLowerCase().trim();
    return text && !ignored.includes(text);
  });
}

const response = $input.first().json;
const prev = $("Parse SEO JSON").first().json;

const modelText = getOpenAIText(response);

let card;

try {
  card = parseJsonLoose(modelText);
} catch (error) {
  throw new Error(`Cannot parse card JSON. Raw model text:\n${modelText}`);
}

const product = prev.product || {};
const seo = prev.seo_keywords || {};
const missingData = cleanMissingData(product.missing_important_data);

const message = `Готово.

Найденные данные товара:
Бренд: ${product.brand || "—"}
Исходное название: ${product.product_name_raw || "—"}
Категория: ${product.category || "—"}
Тип товара: ${product.product_type || "—"}
Назначение: ${product.functional_purpose || "—"}
Артикул: ${product.article || "—"}

Характеристики:
${formatCharacteristics(product.characteristics)}

Цвет:
${list(product.colors)}

Материалы:
${list(product.materials)}

Комплектация:
${list(product.package_contents)}

SEO-ключи

Высокочастотные:
${list(seo.high_frequency_keywords)}

Среднечастотные:
${list(seo.middle_frequency_keywords)}

Низкочастотные / long-tail:
${list(seo.long_tail_keywords)}

Атрибутные:
${list(seo.attribute_keywords)}

Не использовать:
${list(seo.avoid_keywords)}

Наименование для карточки:
${card.title || "—"}

Описание:
${card.description || "—"}

Преимущества:
${list(card.advantages)}

Не хватает данных:
${list(missingData)}

Использованные ключи:
${list(card.used_keywords)}
`;

return [
  {
    json: {
      chat_id: prev.chat_id,
      user_id: prev.user_id,
      input_type: prev.input_type,
      product,
      seo_keywords: seo,
      card,
      message
    }
  }
];

const items = $input.all();

if (!items.length) {
  throw new Error("No input items from Telegram Get File.");
}

const item = items[0];

const binaryKeys = Object.keys(item.binary || {});
if (!binaryKeys.length) {
  throw new Error("No binary image data found. Check Telegram Get File node: Download must be enabled.");
}

const binaryKey = binaryKeys[0];
const bin = item.binary[binaryKey];

// В self-hosted n8n с binaryDataMode=filesystem bin.data может быть не base64,
// поэтому читаем реальный бинарный файл через helper.
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);

if (!buffer || !buffer.length) {
  throw new Error("Binary buffer is empty.");
}

let mimeType = bin.mimeType || "image/jpeg";
const fileName = (bin.fileName || "").toLowerCase();

const allowed = ["image/jpeg", "image/png", "image/gif", "image/webp"];

if (!allowed.includes(mimeType)) {
  if (fileName.endsWith(".png")) {
    mimeType = "image/png";
  } else if (fileName.endsWith(".webp")) {
    mimeType = "image/webp";
  } else if (fileName.endsWith(".gif")) {
    mimeType = "image/gif";
  } else {
    mimeType = "image/jpeg";
  }
}

const base64 = buffer.toString("base64");

return [
  {
    json: {
      ...item.json,
      image_mime_type: mimeType,
      image_size_bytes: buffer.length,
      image_data_url: `data:${mimeType};base64,${base64}`
    },
    binary: item.binary
  }
];

